            val result = JSONObject().apply { put("granted", true) }
            bridge.dispatchToJs(callbackId, result)
        } else {
            pendingNotificationCallback = callbackId
            notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
