class HybridBridge(
    private val activity: HybridWebViewActivity,
    private val webView: WebView
) {
    private val storage: SharedPreferences =
        activity.getSharedPreferences("hybrid_web_storage", Context.MODE_PRIVATE)

    @JavascriptInterface
    fun postMessage(payload: String?) {
        if (payload.isNullOrBlank()) return
        try {
            val json = JSONObject(payload)
            val action = json.optString("action")
            val callbackId = json.optString("callbackId", null)
            val data = json.optJSONObject("data") ?: JSONObject()

            when (action) {
                "camera.requestPermission" -> activity.runOnUiThread {
                    activity.requestCameraPermission(callbackId)
                }

                "storage.set" -> {
                    val key = data.optString("key")
                    val value = data.optString("value")
                    storage.edit().putString(key, value).apply()
                    dispatchToJs(callbackId, JSONObject().put("success", true))
                }

                "storage.get" -> {
                    val key = data.optString("key")
                    val value = storage.getString(key, null)
                    dispatchToJs(
                        callbackId,
                        JSONObject().apply {
                            put("success", true)
                            put("key", key)
                            put("value", value)
                        }
                    )
                }

                "storage.remove" -> {
                    val key = data.optString("key")
                    storage.edit().remove(key).apply()
                    dispatchToJs(callbackId, JSONObject().put("success", true))
                }

                "storage.clear" -> {
                    storage.edit().clear().apply()
                    dispatchToJs(callbackId, JSONObject().put("success", true))
                }

                "push.requestPermission" -> activity.runOnUiThread {
                    activity.requestNotificationPermission(callbackId)
                }

                "push.getToken" -> {
                    val token = storage.getString("push_token", null)
                    dispatchToJs(
                        callbackId,
                        JSONObject().apply {
                            put("success", true)
                            put("token", token)
                        }
                    )
                }

                "push.setToken" -> {
                    val token = data.optString("token", null)
                    storage.edit().putString("push_token", token).apply()
                    dispatchToJs(callbackId, JSONObject().put("success", true))
                }

                else -> {
                    dispatchToJs(
                        callbackId,
                        JSONObject().apply {
                            put("success", false)
                            put("error", "Unknown action: $action")
                        }
                    )
                }
            }
        } catch (e: Exception) {
            dispatchToJs(
                null,
                JSONObject().apply {
                    put("success", false)
                    put("error", e.message ?: "Invalid payload")
                }
            )
        }
    }

    @JavascriptInterface
    fun setStorageItem(key: String, value: String) {
        storage.edit().putString(key, value).apply()
    }

    @JavascriptInterface
    fun getStorageItem(key: String): String? {
        return storage.getString(key, null)
    }

    @JavascriptInterface
    fun removeStorageItem(key: String) {
        storage.edit().remove(key).apply()
    }

    @JavascriptInterface
    fun requestCameraPermission(callbackId: String?) {
        activity.runOnUiThread {
            activity.requestCameraPermission(callbackId)
        }
    }

    @JavascriptInterface
    fun requestPushPermission(callbackId: String?) {
        activity.runOnUiThread {
            activity.requestNotificationPermission(callbackId)
        }
    }

    @JavascriptInterface
    fun getPushToken(): String? {
        return storage.getString("push_token", null)
    }

    fun dispatchToJs(callbackId: String?, result: JSONObject) {
        val envelope = JSONObject().apply {
            put("callbackId", callbackId)
            put("result", result)
        }
        val script = """
            window.HybridNative && window.HybridNative.onNativeResult && window.HybridNative.onNativeResult(${JSONObject.quote(envelope.toString())});
        """.trimIndent()
        activity.runOnUiThread {
            webView.evaluateJavascript(script, null)
        }
    }

    fun dispatchEvent(event: String, data: JSONObject = JSONObject()) {
        val payload = JSONObject().apply {
            put("event", event)
            put("data", data)
        }
        val script = """
            window.HybridNative && window.HybridNative.onNativeEvent && window.HybridNative.onNativeEvent(${JSONObject.quote(payload.toString())});
        """.trimIndent()
        activity.runOnUiThread {
            webView.evaluateJavascript(script, null)
        }
    }
}

object CookieUtils {
    fun configure(webView: WebView) {
        val cookieManager = android.webkit.CookieManager.getInstance()
        cookieManager.setAcceptCookie(true)
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
            cookieManager.setAcceptThirdPartyCookies(webView, true)
        }
    }
}

object HybridWebViewJsContract {
    const val BOOTSTRAP = """
        (function() {
          if (window.HybridNative) return;
          window.HybridNative = {
            callbacks: {},
            call: function(action, data) {
              var callbackId = 'cb_' + Date.now() + '_' + Math.random().toString(36).slice(2);
              return new Promise(function(resolve, reject) {
                window.HybridNative.callbacks[callbackId] = { resolve: resolve, reject: reject };
                NativeBridge.postMessage(JSON.stringify({
                  action: action,
                  callbackId: callbackId,
                  data: data || {}
                }));
              });
            },
            onNativeResult: function(payloadString) {
              try {
                var payload = JSON.parse(payloadString);
                var callback = payload.callbackId && window.HybridNative.callbacks[payload.callbackId];
                if (!callback) return;
                delete window.HybridNative.callbacks[payload.callbackId];
                var result = payload.result || {};
                if (result.success === false || result.granted === false && result.error) {
                  callback.reject(result);
                } else {
                  callback.resolve(result);
                }
              } catch (e) {}
            },
            onNativeEvent: function(payloadString) {
              try {
                var payload = JSON.parse(payloadString);
                window.dispatchEvent(new CustomEvent('HybridNativeEvent', { detail: payload }));
              } catch (e) {}
            }
          };
        })();
    """
}

class HybridWebApp {
    companion object {
        fun injectBridgeBootstrap(webView: WebView) {
            webView.evaluateJavascript(HybridWebViewJsContract.BOOTSTRAP, null)
        }
